# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>

typedef struct FileHandle {
    int id;
    FILE* handle;
    struct FileHandle *next;
} FileHandle;

FileHandle *head = NULL;

void add(int id, const char *filename) {
    FileHandle *new_handle = (FileHandle*)malloc(sizeof(FileHandle));
    new_handle->id = id;
    new_handle->handle = fopen(filename, "r");
    if (!new_handle->handle) {
        free(new_handle);
        return;
    }
    new_handle->next = head;
    head = new_handle;
}

void remove(int id) {
    FileHandle **current = &head;
    while (*current) {
        if ((*current)->id == id) {
            FileHandle *temp = *current;
            *current = temp->next;
            fclose(temp->handle);
            free(temp);
            return;
        }
        current = &((*current)->next);
    }
}

void cleanup() {
    FileHandle *current = head;
    while (current) {
        FileHandle *temp = current;
        current = current->next;
        fclose(temp->handle);
        free(temp);
    }
    head = NULL;
}